// P2 Directory Health Check
// Requer variáveis no n8n:
// SUPABASE_URL=https://xxxx.supabase.co
// SUPABASE_SERVICE_ROLE_KEY=service_role_key

const SUPABASE_URL = $env.SUPABASE_URL || $env.N8N_SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY || $env.N8N_SUPABASE_SERVICE_ROLE_KEY;

if (!SUPABASE_URL || !SUPABASE_KEY) {
  throw new Error('Configure SUPABASE_URL e SUPABASE_SERVICE_ROLE_KEY nas variáveis do n8n.');
}

const input = $input.first().json || {};
const query = input.query || {};
const limit = Number(query.limit || 150);
const mode = String(query.mode || 'safe'); // safe = não desativa por 403/500/timeout

const headers = {
  apikey: SUPABASE_KEY,
  Authorization: `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json',
  Prefer: 'return=minimal'
};

function normalizeUrl(url) {
  if (!url) return null;
  const raw = String(url).trim();
  if (!raw) return null;
  return /^https?:\/\//i.test(raw) ? raw : `https://${raw}`;
}

function classify(httpStatus, errorMessage) {
  if (errorMessage) {
    return { status: 'warning', isActive: true, message: errorMessage };
  }
  if (httpStatus === 404 || httpStatus === 410) {
    return { status: 'inactive', isActive: false, message: `HTTP ${httpStatus}: página não encontrada/removida` };
  }
  if (httpStatus >= 200 && httpStatus < 400) {
    return { status: 'active', isActive: true, message: `HTTP ${httpStatus}: ativo` };
  }
  if ([401, 403, 405, 429].includes(httpStatus)) {
    return { status: 'warning', isActive: true, message: `HTTP ${httpStatus}: exige login, bloqueia HEAD ou limita acesso` };
  }
  if (httpStatus >= 500) {
    return { status: mode === 'strict' ? 'inactive' : 'warning', isActive: mode === 'strict' ? false : true, message: `HTTP ${httpStatus}: instável no momento` };
  }
  return { status: 'warning', isActive: true, message: `HTTP ${httpStatus}: verificar manualmente` };
}

async function supabaseFetch(path, options = {}) {
  const response = await fetch(`${SUPABASE_URL}${path}`, {
    ...options,
    headers: { ...headers, ...(options.headers || {}) },
  });
  if (!response.ok) {
    const text = await response.text().catch(() => '');
    throw new Error(`Supabase ${response.status}: ${text}`);
  }
  if (response.status === 204) return null;
  return response.json();
}

const channels = await supabaseFetch(`/rest/v1/directory_channels?select=code,name,website_url,is_active,submission_type&website_url=not.is.null&order=priority.asc&limit=${limit}`);
const results = [];

for (const channel of channels || []) {
  const url = normalizeUrl(channel.website_url);
  let httpStatus = null;
  let errorMessage = null;

  try {
    const res = await fetch(url, { method: 'HEAD', redirect: 'follow', signal: AbortSignal.timeout(12000) });
    httpStatus = res.status;
    if (httpStatus === 405 || httpStatus === 403) {
      const resGet = await fetch(url, { method: 'GET', redirect: 'follow', signal: AbortSignal.timeout(12000) });
      httpStatus = resGet.status;
    }
  } catch (err) {
    errorMessage = err.message || 'Falha ao acessar URL';
  }

  const classified = classify(httpStatus, errorMessage);
  const checkedAt = new Date().toISOString();
  const updateBody = {
    is_active: classified.isActive,
    last_checked_at: checkedAt,
    last_check_status: classified.status,
    last_check_http_status: httpStatus,
    last_check_message: classified.message,
    updated_at: checkedAt
  };

  await supabaseFetch(`/rest/v1/directory_channels?code=eq.${encodeURIComponent(channel.code)}`, {
    method: 'PATCH',
    body: JSON.stringify(updateBody)
  });

  await supabaseFetch('/rest/v1/directory_channel_checks', {
    method: 'POST',
    body: JSON.stringify({
      channel_code: channel.code,
      checked_at: checkedAt,
      status: classified.status,
      http_status: httpStatus,
      message: classified.message,
      raw_response: { url, previous_is_active: channel.is_active, submission_type: channel.submission_type }
    })
  });

  results.push({
    code: channel.code,
    name: channel.name,
    url,
    httpStatus,
    status: classified.status,
    isActive: classified.isActive,
    message: classified.message
  });
}

return [{
  json: {
    success: true,
    checked: results.length,
    active: results.filter(r => r.isActive).length,
    inactive: results.filter(r => !r.isActive).length,
    timestamp: new Date().toISOString(),
    results
  }
}];
